"""Erreurs."""

from .status import STATUS


class Error(Exception):
    """Une erreur.

    Chaque type d'erreur est associée à un code de status et un message.
    """

    status: STATUS = STATUS.FAILURE
    """ Code de status. """

    message: str = "erreur inconnue"
    """ Message d'erreur. """


class CommandNotFound(Error):
    """Une erreur due à un exécutable introuvable."""

    status = STATUS.NOT_FOUND
    message = "exécutable introuvable"

    def __init__(self, command: str | None = None):
        if command:
            self.message = f"{self.__class__.message}: {command}"
